begin;

update posts set analysis = '{"summary":"2차로에서 주행 중이던 본인 차량이 1차로로 차선을 변경하는 과정에서 발생한 교통사고로 추정됩니다. 사고로 인해 아킬레스 및 종아리 부위 근육 손상이 의심되며 약 8일간 입원 치료를 받았습니다. 상대방 차량의 보험 처리 거부로 인해 추가적인 법적·의료적 조치가 필요한 상황입니다.","chartCode":"차43-1","chartName":"차선변경 중 동일방향 진행 차량과의 충돌","ratio":{"a":{"label":"본인 차량 (2차로→1차로 차선변경 시도)","percent":70},"b":{"label":"상대 차량 (1차로 직진 주행)","percent":30},"reason":"차선변경을 시도한 차량(본인)이 안전 확인 의무를 부담하며 기본 과실이 높으나, 상대방의 과속·방어운전 미흡 여부에 따라 조정 가능합니다."},"laws":[{"name":"도로교통법 제19조","content":"모든 차의 운전자는 차의 진로를 변경하려는 경우에 그 변경하려는 방향으로 오고 있는 다른 차의 정상적인 통행에 장애를 줄 우려가 있을 때에는 진로를 변경하여서는 아니 된다.","relevance":"차선변경 차량의 안전 확인 의무 및 진로변경 금지 조건을 규정","effect":"차선변경 시도 차량(본인)의 과실 가중 요소로 작용"},{"name":"도로교통법 제38조","content":"모든 차의 운전자는 좌회전·우회전·횡단·유턴·서행·정지 또는 후진을 하거나 같은 방향으로 진행하면서 진로를 바꾸려고 하는 경우에는 손이나 방향지시기 또는 등화로써 그 행위가 끝날 때까지 신호를 하여야 한다.","relevance":"차선변경 시 방향지시등 점등 의무 규정","effect":"방향지시등 미점등 확인 시 본인 과실 추가 가중"},{"name":"도로교통법 제48조","content":"모든 차의 운전자는 차를 운전할 때에는 신호 또는 지시에 따르는 동시에 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"안전운전 의무 및 방어운전 의무 규정","effect":"상대방의 과속·방어운전 미흡 시 상대방 과실 가중 가능"}],"cases":[{"title":"차선변경 차량과 직진 차량 충돌 사례 (서울중앙지법 2021)","facts":"2차로에서 1차로로 차선을 변경하던 차량이 1차로를 직진 주행 중이던 차량과 충돌한 사고","ruling":"차선변경 차량 70% : 직진 차량 30%","reason":"차선변경 차량은 후방 및 측방 안전 확인 의무가 있으며, 직진 차량은 정상 통행 중으로 상대적으로 과실이 낮음"},{"title":"고속화도로 차선변경 중 추돌 사례 (부산지법 2020)","facts":"차선변경 차량이 방향지시등 미점등 상태에서 갑자기 차선을 변경하여 직진 차량과 충돌","ruling":"차선변경 차량 80% : 직진 차량 20%","reason":"방향지시등 미점등은 중과실로 인정되어 차선변경 차량 과실이 추가 가중됨"}],"notes":["⚠️ 상대방이 보험 처리를 거부하는 경우, 본인 보험사의 ''자기신체사고'' 또는 ''무보험차상해'' 담보를 통해 먼저 치료비 처리가 가능합니다.","🏥 퇴원 후에도 증상이 지속된다면 MRI 촬영은 반드시 권장됩니다. 아킬레스건 및 종아리 근육 손상은 MRI로만 정확한 진단이 가능합니다.","🏥 퇴원 후 재입원은 의사 소견에 따라 가능합니다. 증상이 악화되거나 지속된다면 재입원 소견서를 요청하세요.","💼 휴업손해(일을 못 하는 기간의 소득 손실)는 상대방에게 청구 가능하며, 진단서·입퇴원확인서·소득 증빙 자료가 필요합니다.","📋 상대방이 보험 처리를 거부할 경우, 경찰 신고 및 금융감독원 민원 접수를 통해 보험 처리를 강제할 수 있습니다.","⚖️ 합의 전 반드시 치료가 완전히 종결된 후 진행하시고, 후유증이 남는 경우 후유장해 진단을 받으시기 바랍니다."],"needed":["사고 발생 당시 정확한 차선변경 위치 및 충돌 지점","방향지시등 점등 여부","상대 차량의 속도 및 차선 위반 여부","블랙박스 영상 또는 CCTV 자료","상대방 차량의 보험 가입 여부 확인","사고 당시 현장 사진 및 경찰 사고 확인서","본인의 직업 및 월 소득 증빙 자료 (휴업손해 청구용)","2차로→1차로 변경 시 상대방 차량과의 거리 및 속도"]}'::jsonb, fault_ratio_a = 70, fault_ratio_b = 30, chart_code = '차43-1', summary = '2차로에서 주행 중이던 본인 차량이 1차로로 차선을 변경하는 과정에서 발생한 교통사고로 추정됩니다. 사고로 인해 아킬레스 및 종아리 부위 근육 손상이 의심되며 약 8일간 입원 치료를 받았습니다. 상대방 차량의 보험 처리 거부로 인해 추가적인 법적·의료적 조치가 필요한 상황입니다.', title = '차선변경 중 후방 추돌 (차43-1)' where id = '2765bf29-5bac-4207-951e-644281ab7e8c';
update posts set analysis = '{"summary":"퇴근 중 피로 상태에서 발생한 교통사고로, 사고 직후 상대방과 원만히 합의하려 했으나 이후 상대방이 보험처리를 요구한 상황입니다. 사고 경위(교차로 진입, 차선변경, 추돌 등)가 구체적으로 제공되지 않아 정확한 과실비율 산정이 어렵습니다. 현재 제공된 정보만으로는 사고 유형 자체를 특정할 수 없습니다.","chartCode":"미확정","chartName":"사고 유형 불명확 - 추가 정보 필요","ratio":{"a":{"label":"본인 차량 (사고 경위 미상)","percent":50},"b":{"label":"상대 차량 (사고 경위 미상)","percent":50},"reason":"사고 유형(교차로 충돌, 추돌, 차선변경 등), 신호 여부, 도로 구조 등 핵심 정보가 없어 현재는 과실비율 추정이 불가합니다. 본인이 더 잘못했다고 인지하고 있으나 구체적 상황 없이는 산정 불가합니다."},"laws":[{"name":"도로교통법 제54조","content":"교통사고 발생 시 운전자는 즉시 정차하여 사상자 구호, 신고 의무를 이행해야 하며, 상호 인적사항을 교환해야 합니다.","relevance":"사고 직후 상대방 차량 사진 미촬영, 인적사항 교환 없이 자리를 떠난 경우 추후 분쟁 시 불리하게 작용할 수 있습니다.","effect":"증거 미확보로 인한 분쟁 발생 시 본인 주장 입증이 어려워질 수 있습니다."},{"name":"도로교통법 제48조","content":"모든 운전자는 안전하고 질서 있는 운전을 할 의무가 있으며, 피로 운전 등 위험 요소를 방지해야 합니다.","relevance":"퇴근 후 피로 상태에서의 운전은 주의의무 위반으로 판단될 수 있습니다.","effect":"피로 운전으로 인한 부주의가 인정될 경우 본인 과실이 가중될 수 있습니다."},{"name":"민법 제750조","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있습니다.","relevance":"구두 합의(쌤쌤) 후 상대방이 번복하여 보험처리를 요구하는 경우, 구두 합의의 법적 효력이 문제될 수 있습니다.","effect":"구두 합의는 서면 증거가 없으면 입증이 어려우므로, 보험사를 통한 공식 처리가 안전합니다."}],"cases":[{"title":"사고 후 구두 합의 후 번복 분쟁 사례","facts":"교통사고 직후 당사자 간 ''쌤쌤(상호 불청구)'' 구두 합의 후, 일방이 귀가한 뒤 상대방이 번복하여 수리비 및 치료비 청구를 요구한 사례","ruling":"구두 합의 효력 불인정, 보험사 과실비율 산정 기준 적용","reason":"구두 합의는 서면 또는 녹취 등 객관적 증거가 없는 경우 법적 효력을 인정받기 어려우며, 결국 사고 상황에 따른 과실비율로 처리됩니다."}],"notes":["⚠️ 현재 사고 유형이 특정되지 않아 정확한 과실비율 산정이 불가능합니다.","구두로 ''쌤쌤'' 합의했더라도 서면/녹취 증거가 없으면 법적 효력이 없을 수 있습니다.","상대방 차량 사진을 못 찍었더라도, 블랙박스 영상이 있다면 즉시 보존하세요.","보험사에 사고를 접수하고 보험사 직원에게 구체적 사고 경위를 설명하면 정확한 과실비율을 안내받을 수 있습니다.","대인 치료비(상해)가 포함된 경우 과실비율에 따른 보상 범위가 달라지므로 보험사 전문가 상담이 필수입니다."],"needed":["🔴 사고 유형: 어떤 상황에서 충돌이 발생했나요? (예: 교차로 진입 중, 직진 중 측면충돌, 후방추돌, 차선변경 중 등)","🔴 충돌 부위: 본인 차량과 상대 차량 각각 어느 부분이 손상되었나요?","🔴 신호 여부: 신호등이 있는 교차로였나요? 당시 신호 상태는?","🔴 도로 구조: 교차로였나요, 직선도로였나요? 편도 몇 차선?","🔴 블랙박스: 본인 또는 상대방 차량 블랙박스 영상이 있나요?","상대방 차량 번호판 또는 인적사항을 확보하셨나요?","상대방이 주장하는 피해 내역(수리비 견적, 치료 부위 등)을 확인하셨나요?"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '미확정', summary = '퇴근 중 피로 상태에서 발생한 교통사고로, 사고 직후 상대방과 원만히 합의하려 했으나 이후 상대방이 보험처리를 요구한 상황입니다. 사고 경위(교차로 진입, 차선변경, 추돌 등)가 구체적으로 제공되지 않아 정확한 과실비율 산정이 어렵습니다. 현재 제공된 정보만으로는 사고 유형 자체를 특정할 수 없습니다.', title = '퇴근 중 피로 상태에서 발생한 교통사고로, 사고 직후' where id = 'a130ec86-19f1-43ed-8cf8-7e7a9bae99f6';

commit;
